import { useParams } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { fetchGroupById } from '../services/api';
import '../styles/GroupDetails';
export default function GroupDetails() {
    const { groupId } = useParams();
    const [group, setGroup] = useState(null);

    useEffect(() => {
        fetchGroupById(groupId).then(setGroup);
    }, [groupId]);

    if (!group) {
        return <div className="p-6 text-center">Chargement...</div>;
    }

    return (
        <div className="group-details-container">
            <h1 className="group-title">{group.name}</h1>

            {/* Bannière */}
            <div className="group-banner">
                <img src={group.image} alt={group.name} className="group-banner-image" />
            </div>

            {/* Section Commentaires */}
            <section className="group-section">
                <h2 className="section-title">Commentaires des utilisateurs</h2>
                <ul className="comments-list">
                    {group.comments && group.comments.length > 0 ? (
                        group.comments.map((comment, idx) => (
                            <li key={idx} className="comment-item">
                                <strong>{comment.user} :</strong> {comment.text}
                            </li>
                        ))
                    ) : (
                        <p className="text-sm text-gray-500">Aucun commentaire pour le moment.</p>
                    )}
                </ul>
            </section>

            {/* Section Membres */}
            <section className="group-section">
                <h2 className="section-title">Membres du groupe</h2>
                <ul className="members-list">
                    {group.members.map((member, idx) => (
                        <li key={idx} className="member-item">{member}</li>
                    ))}
                </ul>
            </section>
        </div>
    );
}
